136.query:
timeseries {
  availability_series = avg(dt.synthetic.browser.availability)
},
by: {
  dt.entity.synthetic_test,
  dt.entity.synthetic_location
}
| fieldsAdd monitor_name = entityAttr(dt.entity.synthetic_test, "entity.name")
| summarize {
    monitor_name = takeFirst(monitor_name),
    availability = avg(arrayAvg(availability_series))
  }, by: { dt.entity.synthetic_test }
| fieldsRename `Monitor_Name` = monitor_name, `Availability (%)` = availability

| join [
fetch dt.system.events
| filter event.kind == "BILLING_USAGE_EVENT"
| filter event.type == "Browser Monitor or Clickpath"
| fieldsAdd entityName(dt.entity.synthetic_test)
| summarize totalBilledActions = sum(billed_synthetic_action_count), by:{dt.entity.synthetic_test.name}
| lookup [
  fetch dt.entity.synthetic_test
  | fieldsAdd assignedLocations, syntheticMonitorFrequency, steps
  | fieldsAdd locationCount = arraySize(assignedLocations), stepsCount = arraySize(steps)
  | fieldsRemove assignedLocations, steps
  ], sourceField: dt.entity.synthetic_test.name, lookupField: entity.name, fields: {locationCount, stepsCount, syntheticMonitorFrequency}
| fieldsRename `Monitor_Name` = dt.entity.synthetic_test.name
], on: {Monitor_Name}, kind: outer
| fieldsRename `Frequency` = right.syntheticMonitorFrequency, `Locations` = right.locationCount, `Steps` = right.stepsCount
| filterOut isNull(Monitor_Name)
| fieldsAdd Cost = (right.totalBilledActions/100000)*toDouble($Browser_Synthetic_Cost)
| sort Cost desc
